# pip install openai sqlalchemy psycopg2-binary (or sqlite for local dev)
import json
from openai import OpenAI
from sqlalchemy import create_engine, text

engine = create_engine("sqlite:///orders.db")   # or postgresql://...
client = OpenAI()

# --- Tool implementations ---

def get_order(order_id: str) -> dict | None:
    with engine.connect() as conn:
        row = conn.execute(
            text("SELECT id, customer_name, total, status FROM orders WHERE id = :id"),
            {"id": order_id},
        ).fetchone()
    if row is None:
        return None
    return {"id": row.id, "customer": row.customer_name,
            "total": row.total, "status": row.status}

def list_orders_by_status(status: str, limit: int = 10) -> list[dict]:
    with engine.connect() as conn:
        rows = conn.execute(
            text("SELECT id, customer_name, total FROM orders "
                 "WHERE status = :status ORDER BY created_at DESC LIMIT :limit"),
            {"status": status, "limit": limit},
        ).fetchall()
    return [{"id": r.id, "customer": r.customer_name, "total": r.total} for r in rows]

# --- Tool schemas ---

TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "get_order",
            "description": (
                "Retrieve a single order by its ID. Use when the user references "
                "a specific order number (e.g. 'ORD-1042'). Returns order details "
                "including customer, total, and status."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "order_id": {
                        "type": "string",
                        "description": "The order ID, e.g. 'ORD-1042'.",
                    }
                },
                "required": ["order_id"],
                "additionalProperties": False,
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "list_orders_by_status",
            "description": (
                "List recent orders filtered by status. Use when the user asks "
                "about pending, completed, or cancelled orders. Returns up to 10 "
                "most recent orders by default."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "status": {
                        "type": "string",
                        "enum": ["pending", "processing", "completed", "cancelled"],
                        "description": "Order status to filter by.",
                    },
                    "limit": {
                        "type": "integer",
                        "description": "Max results to return (1-50).",
                        "default": 10,
                        "minimum": 1,
                        "maximum": 50,
                    },
                },
                "required": ["status"],
                "additionalProperties": False,
            },
        },
    },
]

TOOL_MAP = {
    "get_order": get_order,
    "list_orders_by_status": list_orders_by_status,
}

def format_db_result(result) -> str:
    if result is None:
        return "No record found."
    return json.dumps(result, default=str, indent=2)

def run_agent(user_message: str) -> str:
    messages = [{"role": "user", "content": user_message}]
    while True:
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=messages,
            tools=TOOLS,
            tool_choice="auto",
        )
        choice = response.choices[0]
        messages.append(choice.message)
        if choice.finish_reason == "stop":
            return choice.message.content
        for tc in choice.message.tool_calls:
            args = json.loads(tc.function.arguments)
            result = TOOL_MAP[tc.function.name](**args)
            messages.append({
                "role": "tool",
                "tool_call_id": tc.id,
                "content": format_db_result(result),
            })

print(run_agent("Show me the 5 most recent pending orders."))
print(run_agent("What is the status of order ORD-1042?"))

import re
from openai import OpenAI
from sqlalchemy import create_engine, text

engine = create_engine("sqlite:///sales.db")
client = OpenAI()

SQL_TOOL = {
    "type": "function",
    "function": {
        "name": "run_sql_query",
        "description": (
            "Execute a read-only SQL SELECT query against the sales database. "
            "Use this when the user asks analytical questions about orders, "
            "products, or customers that require aggregation or filtering. "
            "Only SELECT statements are permitted."
        ),
        "parameters": {
            "type": "object",
            "properties": {
                "sql": {
                    "type": "string",
                    "description": (
                        "A valid SQLite SELECT statement. "
                        "Must not contain INSERT, UPDATE, DELETE, DROP, or ALTER."
                    ),
                },
            },
            "required": ["sql"],
            "additionalProperties": False,
        },
    },
}

FORBIDDEN = re.compile(
    r"\b(INSERT|UPDATE|DELETE|DROP|ALTER|CREATE|TRUNCATE)\b",
    re.IGNORECASE,
)

def run_sql_query(sql: str) -> str:
    if FORBIDDEN.search(sql):
        return "Error: only SELECT queries are permitted."
    try:
        with engine.connect() as conn:
            rows = conn.execute(text(sql)).fetchmany(50)   # cap at 50 rows
        if not rows:
            return "Query returned no rows."
        headers = list(rows[0]._fields)
        lines = [" | ".join(headers)]
        lines += [" | ".join(str(v) for v in row) for row in rows]
        return "\n".join(lines)
    except Exception as e:
        return f"SQL error: {e}"

system_prompt = f"""You are a data assistant.
{get_schema_prompt(engine)}

Only generate SELECT queries. Never modify data.
Limit result sets to 20 rows unless the user asks for more.
"""

def run_sql_agent(user_message: str) -> str:
    messages = [
        {"role": "system", "content": system_prompt},
        {"role": "user", "content": user_message},
    ]
    while True:
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            messages=messages,
            tools=[SQL_TOOL],
            tool_choice="auto",
        )
        choice = response.choices[0]
        messages.append(choice.message)
        if choice.finish_reason == "stop":
            return choice.message.content
        for tc in choice.message.tool_calls:
            args = json.loads(tc.function.arguments)
            result = run_sql_query(**args)
            messages.append({
                "role": "tool",
                "tool_call_id": tc.id,
                "content": result,
            })

print(run_sql_agent("What are the top 5 products by revenue this month?"))

# pip install redis
import redis
import json

r = redis.Redis(host="localhost", port=6379, decode_responses=True)

def get_user_session(session_id: str) -> dict | None:
    data = r.hgetall(f"session:{session_id}")
    return data if data else None

def get_product_cache(product_id: str) -> dict | None:
    raw = r.get(f"product:{product_id}")
    if raw is None:
        return None
    return json.loads(raw)

REDIS_TOOLS = [
    {
        "type": "function",
        "function": {
            "name": "get_user_session",
            "description": (
                "Retrieve an active user session by session ID. Returns user ID, "
                "login time, and preferences. Returns null if session is expired or not found."
            ),
            "parameters": {
                "type": "object",
                "properties": {
                    "session_id": {"type": "string", "description": "Session token UUID."},
                },
                "required": ["session_id"],
                "additionalProperties": False,
            },
        },
    },
]

# pip install pymongo
from pymongo import MongoClient
import json

mongo = MongoClient("mongodb://localhost:27017/")
db = mongo["ecommerce"]

def find_products(
    category: str | None = None,
    max_price: float | None = None,
    in_stock: bool = True,
    limit: int = 10,
) -> list[dict]:
    query: dict = {}
    if category:
        query["category"] = category
    if max_price is not None:
        query["price"] = {"$lte": max_price}
    if in_stock:
        query["stock"] = {"$gt": 0}
    cursor = db.products.find(query, {"_id": 0}).limit(limit)
    return list(cursor)

MONGO_TOOL = {
    "type": "function",
    "function": {
        "name": "find_products",
        "description": (
            "Search the product catalog. Use when the user asks about available products, "
            "prices, or stock levels. Supports filtering by category, maximum price, and "
            "in-stock status."
        ),
        "parameters": {
            "type": "object",
            "properties": {
                "category": {
                    "anyOf": [{"type": "string"}, {"type": "null"}],
                    "description": "Product category filter, e.g. 'electronics'. Null for all.",
                    "default": None,
                },
                "max_price": {
                    "anyOf": [{"type": "number"}, {"type": "null"}],
                    "description": "Maximum price in USD. Null for no price filter.",
                    "default": None,
                },
                "in_stock": {
                    "type": "boolean",
                    "description": "If true, return only in-stock items.",
                    "default": True,
                },
                "limit": {
