# Read-only connection via SQLAlchemy — PostgreSQL example
# Create a dedicated DB user with SELECT only:
#   CREATE USER llm_reader WITH PASSWORD 'secret';
#   GRANT SELECT ON ALL TABLES IN SCHEMA public TO llm_reader;

from sqlalchemy import create_engine, event
from sqlalchemy.exc import OperationalError

engine = create_engine(
    "postgresql://llm_reader:secret@localhost/sales",
    connect_args={"connect_timeout": 5},
    pool_pre_ping=True,
)

# Belt-and-suspenders: also block writes at the connection level
@event.listens_for(engine, "connect")
def set_readonly(dbapi_conn, connection_record):
    dbapi_conn.set_session(readonly=True, autocommit=True)
